Hello, I've tried to extend @hvdklauw 's solution to a 3 level deep nested router. Here's the code:

    class NestedHyperlinkedIdentityField(HyperlinkedIdentityField):
        """
        """
        parent_parent_lookup_field = None
        parent_parent_lookup_url_kwarg = None
        parent_lookup_field = None
        parent_lookup_url_kwarg = None

        def __init__(self, *args, **kwargs):
            """Constructor."""
            self.parent_lookup_field = kwargs.pop('parent_lookup_field', None)
            self.parent_lookup_url_kwarg = (
                kwargs.pop('parent_lookup_url_kwarg', None) or (
                    self.parent_lookup_field
                )
            )
            self.parent_parent_lookup_field = kwargs.pop(
                'parent_parent_lookup_field',
                None
            )
            self.parent_parent_lookup_url_kwarg = (
                kwargs.pop('parent_parent_lookup_url_kwarg', None) or (
                    self.parent_parent_lookup_field
                )
            )

            super(NestedHyperlinkedIdentityField, self).__init__(*args, **kwargs)

    def get_url(self, obj, view_name, request, format):
            """Get the url for the field."""
            # Unsaved objects will not yet have a valid URL.
            if hasattr(obj, 'pk') and obj.pk is None:
                return None

            lookup_value = getattr(obj, self.lookup_field)
            kwargs = {self.lookup_url_kwarg: lookup_value}
            if self.parent_lookup_field:
                kwargs[self.parent_lookup_url_kwarg] = (
                    getattr(obj, self.parent_lookup_field)
                )
            if self.parent_parent_lookup_field:
                kwargs[self.parent_parent_lookup_url_kwarg] = (
                    getattr(obj, self.parent_parent_lookup_field)
                )

            return self.reverse(
                view_name,
                kwargs=kwargs,
                request=request,
                format=format
            )

The 2 level deep continues to work with this solution, but a 3 level deep one throws the lookup_field error. Django shows me that the router is generating URLs and viewnames as it should.

Extending the example in the README:
    class MailDropSerializer(HyperlinkedModelSerializer):
